parameters.jsCode:
const ctx = $('PREPARE_CONTEXT').item.json;
let raw = $input.item.json.output || {};

if (typeof raw === 'string') {
  try {
    raw = JSON.parse(raw.replace(/```json|```/g, '').trim());
  } catch (e) {
    raw = { full_user_profile: raw, summary_user_profile: '' };
  }
}

const full    = raw.full_user_profile    || JSON.stringify(ctx.user_profile) || '';
const summary = raw.summary_user_profile || '';

const esc = s => String(s).replace(/'/g, "''");

return {
  json: {
    full_user_profile:    full,
    summary_user_profile: summary,
    user_id:              ctx.user_id,
    contact_id:           ctx.contact_id,
    account_id:           ctx.account_id,
    base_url:             ctx.base_url,
    user_token:           ctx.user_token,
    save_profile_sql:     `UPDATE users SET user_profile = '${esc(JSON.stringify({ full: full, summary: summary }))}'::jsonb, updated_at = NOW() WHERE user_id = '${esc(ctx.user_id)}';`
  }
};

