const raw = String($input.item.json.output || '');

const clean = raw
  .replace(/Calling\s+\w[\w_]*\s+with[\s\S]*?\}/gi, '')
  .replace(/\{\s*"[^"]+"\s*:[\s\S]*?\}/g, '')
  .replace(/```[\s\S]*?```/g, '')
  .replace(/^(Tool|Function|Action)\s*:.*$/gim, '')
  .replace(/\*{1,3}([^*]+)\*{1,3}/g, '$1')
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return {
  json: {
    message: clean || 'Olá! Passei para ver se posso ajudar em algo. 😊'
  }
};

